const PAGE=typeof document==="undefined"?"":document.body.dataset.page,API="/api";
const NEXT_STATUS={PLACED:"CONFIRMED",CONFIRMED:"PACKED",ASSIGNED:"PICKED_UP",PICKED_UP:"OUT_FOR_DELIVERY",OUT_FOR_DELIVERY:"DELIVERY_VERIFICATION"};
const STATUS_FLOW=["SCHEDULED","PLACED","CONFIRMED","PACKED","ASSIGNED","PICKED_UP","OUT_FOR_DELIVERY","DELIVERY_VERIFICATION","DELIVERED"];
const ZONE_COORDS={1:[12.9719,77.6412],2:[12.9352,77.6245],3:[12.9757,77.605],4:[12.9116,77.6389],5:[12.9698,77.75]};
const app=typeof document==="undefined"?null:document.querySelector("#app");
const read=(key,fallback)=>{try{return JSON.parse(localStorage.getItem(key))??fallback}catch{return fallback}};
const state=typeof localStorage==="undefined"?{session:null}:{session:read("relay_session",null),category:null,search:"",polling:true,cartSaves:new Map(),cartPending:new Set(),adminFilters:{productSearch:"",category:"ALL",stock:"ALL",orderSearch:"",orderStatus:"ALL"}};

export const formatStatus=value=>String(value||"").toLowerCase().replaceAll("_"," ").replace(/^./,c=>c.toUpperCase());
export const validCoordinates=(lat,lng)=>Number.isFinite(lat)&&Number.isFinite(lng)&&lat>=-90&&lat<=90&&lng>=-180&&lng<=180;
export const canTransition=(from,to)=>({SCHEDULED:["PLACED","CANCELLED"],PLACED:["CONFIRMED","CANCELLED"],CONFIRMED:["PACKED","CANCELLED"],PACKED:["ASSIGNED","CANCELLED"],ASSIGNED:["PICKED_UP","CANCELLED"],PICKED_UP:["OUT_FOR_DELIVERY"],OUT_FOR_DELIVERY:["DELIVERY_VERIFICATION"],DELIVERY_VERIFICATION:["DELIVERED"],DELIVERED:[],CANCELLED:[]}[from]||[]).includes(to);
const esc=value=>String(value??"").replace(/[&<>'"]/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;","'":"&#39;",'"':"&quot;"}[c]));
const money=value=>new Intl.NumberFormat("en-IN",{style:"currency",currency:"INR",minimumFractionDigits:0,maximumFractionDigits:2}).format(Number(value)||0);
const date=value=>value?new Intl.DateTimeFormat("en-IN",{dateStyle:"medium",timeStyle:"short"}).format(new Date(value)):"-";
const uuid=()=>globalThis.crypto?.randomUUID?.()||`relay-${Date.now()}-${Math.random().toString(36).slice(2)}`;

async function api(path,options={}){
  const headers={...(options.body?{"Content-Type":"application/json"}:{}),...options.headers};
  if(state.session?.token)headers.Authorization=`Bearer ${state.session.token}`;
  let response,timedOut=false;const controller=new AbortController(),abort=()=>controller.abort(options.signal?.reason);
  if(options.signal?.aborted)abort();else options.signal?.addEventListener("abort",abort,{once:true});
  const timeout=setTimeout(()=>{timedOut=true;controller.abort()},12000);
  try{response=await fetch(`${API}${path}`,{...options,headers,signal:controller.signal})}catch(error){
    if(timedOut)throw new Error("Relay timed out. Try again.");
    if(error.name==="AbortError")throw error;
    throw new Error(typeof navigator!=="undefined"&&!navigator.onLine?"You are offline. Reconnect to continue.":"Relay is unreachable. Check the Java server.");
  }finally{clearTimeout(timeout);options.signal?.removeEventListener("abort",abort)}
  const text=await response.text();let data={};
  try{data=text?JSON.parse(text):{}}catch{throw new Error(response.ok?"Relay returned an invalid response.":`Request failed (${response.status})`)}
  if(response.status===401&&PAGE!=="auth")logout(false);
  if(!response.ok)throw new Error(data.error||`Request failed (${response.status})`);return data;
}

function topbar(context,{cart=false}={}){
  const user=state.session.user;
  return `<header class="topbar"><div class="topbar-inner"><a class="brand" href="#" aria-label="Relay home"><span class="brand-mark">R/</span><span>Relay<small>market network</small></span></a>
    <span class="top-context">${esc(context)}</span><div class="top-actions">${cart?`<button type="button" class="icon-btn cart-button" data-action="cart" title="Open cart" aria-label="Open cart"><span class="cart-mark"></span><span class="cart-count">${state.cart?.items?.length||0}</span></button>`:""}
    <span class="profile-chip">${esc(user.name)}</span><button type="button" class="icon-btn" data-action="logout" title="Sign out" aria-label="Sign out">&#x2192;</button></div></div></header>`;
}
function bindGlobal(){document.querySelector('[data-action="logout"]')?.addEventListener("click",()=>logout(true));document.querySelector('[data-action="cart"]')?.addEventListener("click",()=>document.querySelector(".cart-rail")?.scrollIntoView({behavior:"smooth",block:"start"}));}
function logout(callApi){state.polling=false;clearTimeout(state.pollTimer);stopLocation(false);const token=state.session?.token;state.session=null;localStorage.removeItem("relay_session");if(callApi&&token)fetch(`${API}/auth/logout`,{method:"POST",headers:{Authorization:`Bearer ${token}`},keepalive:true}).catch(()=>{});location.replace("index.html");}
function toast(message,type="info"){
  let stack=document.querySelector(".toast-stack");if(!stack){stack=document.createElement("div");stack.className="toast-stack";stack.setAttribute("aria-live","polite");stack.setAttribute("aria-atomic","true");document.body.append(stack)}
  const item=document.createElement("div");item.className=`toast ${type}`;item.setAttribute("role","status");item.textContent=message;stack.append(item);requestAnimationFrame(()=>item.classList.add("is-open"));
  setTimeout(()=>{item.classList.add("is-closing");item.addEventListener("transitionend",event=>{if(event.propertyName==="transform")item.remove()},{once:true})},3500);
}
function setButtonLoading(button,loading,label){if(!button)return;if(loading){button.dataset.idleLabel=button.textContent;button.disabled=true;button.classList.add("is-loading");button.setAttribute("aria-busy","true");if(label)button.textContent=label}else{button.disabled=false;button.classList.remove("is-loading");button.removeAttribute("aria-busy");if(button.dataset.idleLabel){button.textContent=button.dataset.idleLabel;delete button.dataset.idleLabel}}}
function openModal(trigger,{title,body,wide=false,footer=""}){
  const point=trigger?.getBoundingClientRect?(()=>{const r=trigger.getBoundingClientRect();return{x:r.left+r.width/2,y:r.top+r.height/2}})():{x:innerWidth/2,y:innerHeight/2};
  const layer=document.createElement("div");layer.className="modal-layer";layer.innerHTML=`<section class="modal-panel ${wide?"is-wide":""}" role="dialog" aria-modal="true" aria-labelledby="modal-title"><header class="modal-head"><h2 id="modal-title">${esc(title)}</h2><button type="button" class="icon-btn" data-close title="Close" aria-label="Close">X</button></header><div class="modal-body">${body}</div>${footer?`<footer class="modal-foot">${footer}</footer>`:""}</section>`;
  document.body.append(layer);document.body.classList.add("modal-open");const panel=layer.querySelector(".modal-panel"),rect=panel.getBoundingClientRect();panel.style.transformOrigin=`${point.x-rect.left}px ${point.y-rect.top}px`;let isOpen=true,closeTimer;
  const cleanup=()=>{if(!isOpen)return;isOpen=false;clearTimeout(closeTimer);document.removeEventListener("keydown",onKey);layer.dispatchEvent(new Event("modalclose"));layer.remove();if(!document.querySelector(".modal-layer"))document.body.classList.remove("modal-open");trigger?.focus?.()};
  const close=()=>{if(!isOpen||layer.classList.contains("is-closing"))return;layer.classList.add("is-closing");layer.classList.remove("is-open");panel.addEventListener("transitionend",event=>{if(event.propertyName==="transform")cleanup()});closeTimer=setTimeout(cleanup,400)};
  const onKey=event=>{if(event.key==="Escape")close();if(event.key==="Tab"){const focus=[...panel.querySelectorAll('button:not(:disabled),input:not(:disabled),select:not(:disabled),textarea:not(:disabled),[href]')];if(!focus.length)return;const first=focus[0],last=focus.at(-1);if(event.shiftKey&&document.activeElement===first){event.preventDefault();last.focus()}else if(!event.shiftKey&&document.activeElement===last){event.preventDefault();first.focus()}}};
  layer.addEventListener("click",event=>{if(event.target===layer||event.target.closest("[data-close]"))close()});document.addEventListener("keydown",onKey);requestAnimationFrame(()=>layer.classList.add("is-open"));panel.querySelector("input,select,button")?.focus();return{layer,panel,close,get isOpen(){return isOpen}};
}
function skeleton(count=4){return `<div class="skeleton-grid">${Array.from({length:count},()=>'<div class="skeleton"></div>').join("")}</div>`}
function flyToCart(source,onLand=()=>{}){const target=document.querySelector(".cart-button");if(!source||!target){onLand();return}const from=source.getBoundingClientRect(),to=target.getBoundingClientRect(),clone=source.cloneNode(true);clone.classList.add("fly-token");Object.assign(clone.style,{left:`${from.left}px`,top:`${from.top}px`,width:`${from.width}px`,height:`${from.height}px`});clone.style.setProperty("--fly-x",`${to.left+to.width/2-from.left-from.width/2}px`);clone.style.setProperty("--fly-y",`${to.top+to.height/2-from.top-from.height/2}px`);document.body.append(clone);let landed=false;const land=()=>{if(landed)return;landed=true;clone.remove();onLand();const cart=document.querySelector(".cart-button");if(cart){cart.classList.add("is-landing");setTimeout(()=>cart.classList.remove("is-landing"),350)}};requestAnimationFrame(()=>clone.classList.add("is-flying"));clone.addEventListener("transitionend",event=>{if(event.propertyName==="transform")land()});setTimeout(land,650)}

function priceLabel(product){if(product.pricingType==="WEIGHT")return `${money(product.pricePerKg)}/kg`;if(product.pricingType==="VARIANT"){const prices=product.variants.map(v=>Number(v.unitPrice||v.pricePerKg)).filter(Boolean);return prices.length?`From ${money(Math.min(...prices))}`:"Unavailable"}return money(product.unitPrice)}
function stockOf(product,variantId){if(variantId){return product.variants.find(v=>v.id===Number(variantId))?.stockQuantity||0}return product.stockQuantity}
function badges(product){return [product.fragile?"Fragile":"",product.temperatureControlled?"Chilled":"",product.requiresInsurance?"Insured":""].filter(Boolean).map(x=>`<span class="micro-badge">${x}</span>`).join("")}
function productCard(product){return `<article class="product-card"><button type="button" class="product-media" data-product="${product.id}" aria-label="Open ${esc(product.name)} details"><img src="${esc(product.imageUrl)}" alt="${esc(product.name)}" loading="lazy"><span class="category-label">${esc(product.categoryName)}</span></button><div class="product-copy"><h3>${esc(product.name)}</h3><p>${esc(product.description)}</p><div class="badge-row">${badges(product)}</div><div class="product-buy"><div><strong>${priceLabel(product)}</strong><small>${product.pricingType==="WEIGHT"?`${product.minimumOrderWeight}-${product.maximumOrderWeight} kg`:product.unitWeightKg?`${product.unitWeightKg} kg`:"Choose a variant"}</small></div><button type="button" class="add-square" data-quick-add="${product.id}" aria-label="Add ${esc(product.name)}">+</button></div></div></article>`}
function orderCard(order){return `<article class="order-card" data-order="${order.id}" tabindex="0" role="button" aria-label="Open order ${order.id}"><div class="order-top"><span class="order-id">RLY-${String(order.id).padStart(4,"0")}</span><span class="status-pill" data-status="${order.status}">${formatStatus(order.status)}</span></div>${order.orderType==="GIFT"?`<span class="gift-badge">Gift / ${esc(formatStatus(order.occasion||"scheduled"))}</span>`:""}<div class="route-strip"><span></span><div><small>From</small>${esc(order.pickupZone)}</div><i></i><div><small>To</small>${esc(order.dropZone)}</div></div><div class="order-foot"><span>${order.scheduledDeliveryAt?`Scheduled ${date(order.scheduledDeliveryAt)}`:date(order.createdAt)}</span><strong>${money(order.price)}</strong></div></article>`}

async function loadCustomer(showSkeleton=true){
  if(showSkeleton){app.innerHTML=`${topbar("Marketplace",{cart:true})}<main class="workspace">${skeleton()}</main>`;bindGlobal()}
  const [categories,products,cart,orders,zones,addresses]=await Promise.all([api("/categories"),api("/products"),api("/cart"),api("/orders"),api("/zones"),api("/addresses")]);
  const old=state.orders?.map(o=>`${o.id}:${o.status}`).join("|");Object.assign(state,{categories,products,cart,orders,zones,addresses});
  if(!showSkeleton&&old&&old!==orders.map(o=>`${o.id}:${o.status}`).join("|"))toast("A delivery status changed.");renderCustomer();
}
function renderCustomer(){
  const address=state.addresses.find(a=>a.isDefault)||state.addresses[0];
  app.innerHTML=`${topbar("Marketplace",{cart:true})}<main class="workspace marketplace"><header class="market-head"><button type="button" class="location-control" data-location><span class="location-dot"></span><span><small>Deliver to</small>${esc(address?.label||"Set location")} / ${esc(address?.addressLine||"Choose an address")}</span></button><div class="search-shell"><span aria-hidden="true">⌕</span><input type="search" data-search value="${esc(state.search)}" placeholder="Search products and essentials" aria-label="Search products"></div></header>
    <nav class="category-rail" aria-label="Product categories"><button type="button" class="category-chip ${state.category?"":"is-active"}" data-category="">All</button>${state.categories.map(c=>`<button type="button" class="category-chip ${state.category===c.id?"is-active":""}" data-category="${c.id}">${esc(c.name)}</button>`).join("")}</nav>
    <div class="commerce-grid"><section data-catalog>${catalogMarkup()}</section>${cartPanel()}</div>
    <section class="history-band">${historyMarkup()}</section></main>`;
  bindGlobal();bindCustomer();
}
function filteredProducts(){let products=state.products;if(state.category)products=products.filter(p=>p.categoryId===state.category);if(state.search)products=products.filter(p=>`${p.name} ${p.description}`.toLowerCase().includes(state.search));return products}
function catalogMarkup(){const products=filteredProducts();return `<div class="section-head"><div><span class="section-kicker">${state.category?esc(state.categories.find(c=>c.id===state.category)?.name):"Today’s catalog"}</span><h1>${state.search?`Results for “${esc(state.search)}”`:"Shop the city in one route."}</h1></div><span class="muted mono">${products.length} products</span></div>${products.length?`<div class="product-grid">${products.map(productCard).join("")}</div>`:'<div class="empty-state"><div><strong>No matching products</strong>Clear the search or choose another category.</div></div>'}`}
function historyMarkup(){return `<div class="section-head"><div><span class="section-kicker">Delivery ledger</span><h2>Orders and gifts</h2></div></div>${state.orders.length?`<div class="orders-grid">${state.orders.map(orderCard).join("")}</div>`:'<div class="empty-state"><div><strong>No orders yet</strong>Add a product to begin.</div></div>'}`}
function patchCatalog(){const section=document.querySelector("[data-catalog]");if(section){section.innerHTML=catalogMarkup();bindProductControls()}document.querySelectorAll("[data-category]").forEach(button=>button.classList.toggle("is-active",(button.dataset.category?Number(button.dataset.category):null)===state.category))}
function patchHistory(){const band=document.querySelector(".history-band");if(band){band.innerHTML=historyMarkup();bindOrderControls()}}
function patchLocation(){const address=state.addresses.find(a=>a.isDefault)||state.addresses[0],label=document.querySelector("[data-location] span:last-child");if(label)label.innerHTML=`<small>Deliver to</small>${esc(address?.label||"Set location")} / ${esc(address?.addressLine||"Choose an address")}`}
function cartPanel(){
  const lines=state.cart.items||[],subtotal=lines.reduce((sum,line)=>{const p=line.product,v=p.variants.find(x=>x.id===line.variantId);return sum+(p.pricingType==="WEIGHT"?Number(p.pricePerKg)*Number(line.selectedWeightKg):Number(v?.unitPrice||p.unitPrice)*line.quantity)},0);
  return `<aside class="cart-rail"><div class="cart-title"><div><span class="section-kicker">Cart / ${lines.length}</span><h2>Route summary</h2></div><span class="cart-orbit"></span></div><div class="cart-items">${lines.length?lines.map(cartLine).join(""):'<div class="empty-cart">Products you add will land here.</div>'}</div><div class="cart-total"><span>Items estimate</span><strong>${money(subtotal)}</strong></div><button type="button" class="btn btn-accent btn-wide" data-checkout ${lines.length?"":"disabled"}>Review delivery price</button><small class="cart-note">Delivery, handling, tax and gift charges appear in the verified quote.</small></aside>`;
}
function cartLine(line){const p=line.product,v=p.variants.find(x=>x.id===line.variantId),weight=p.pricingType==="WEIGHT",pending=state.cartPending.has(p.id);return `<div class="cart-line ${pending?"is-updating":""}"><img src="${esc(p.imageUrl)}" alt=""><div><strong>${esc(p.name)}</strong><small>${esc(v?.label||(weight?`${line.selectedWeightKg} kg`:"Standard"))}${pending?" / Updating…":""}</small><div class="stepper"><button type="button" data-cart-step="${line.id}" data-delta="-1" aria-label="Decrease ${weight?"weight":"quantity"}" ${pending?"disabled":""}>−</button><span>${weight?`${line.selectedWeightKg} kg`:line.quantity}</span><button type="button" data-cart-step="${line.id}" data-delta="1" aria-label="Increase ${weight?"weight":"quantity"}" ${pending?"disabled":""}>+</button></div></div><button type="button" class="remove-item" data-cart-remove="${line.id}" aria-label="Remove ${esc(p.name)}" ${pending?"disabled":""}>X</button></div>`}
function bindCustomer(){
  let searchTimer;document.querySelector("[data-search]")?.addEventListener("input",event=>{clearTimeout(searchTimer);searchTimer=setTimeout(()=>{state.search=event.target.value.trim().toLowerCase();patchCatalog()},160)});
  document.querySelectorAll("[data-category]").forEach(button=>button.addEventListener("click",()=>{state.category=button.dataset.category?Number(button.dataset.category):null;patchCatalog()}));
  bindProductControls();bindCartControls();bindOrderControls();
  document.querySelector("[data-location]")?.addEventListener("click",event=>addressModal(event.currentTarget));
}
function bindProductControls(){document.querySelectorAll("[data-product]").forEach(button=>button.addEventListener("click",()=>showProduct(button,Number(button.dataset.product))));document.querySelectorAll("[data-quick-add]").forEach(button=>button.addEventListener("click",()=>quickAdd(button,Number(button.dataset.quickAdd))))}
function bindOrderControls(){document.querySelectorAll("[data-order]").forEach(card=>{const open=()=>showOrder(card,Number(card.dataset.order));card.addEventListener("click",open);card.addEventListener("keydown",e=>{if(["Enter"," "].includes(e.key)){e.preventDefault();open()}})})}
function bindCartControls(){document.querySelectorAll("[data-cart-step]").forEach(button=>button.addEventListener("click",()=>changeCart(button)));document.querySelectorAll("[data-cart-remove]").forEach(button=>button.addEventListener("click",()=>removeCartItem(button.dataset.cartRemove)));document.querySelector("[data-checkout]")?.addEventListener("click",event=>checkout(event.currentTarget))}
function patchCart(){const rail=document.querySelector(".cart-rail");if(rail){rail.outerHTML=cartPanel();bindCartControls()}const count=document.querySelector(".cart-count");if(count)count.textContent=state.cart.items.length}
function cartCopy(){return{...state.cart,items:state.cart.items.map(item=>({...item}))}}
function optimisticAdd(product,body){const items=state.cart.items.map(item=>({...item})),existing=items.find(item=>item.productId===product.id&&(item.variantId||null)===(body.variantId||null));if(existing){if(product.pricingType==="WEIGHT"){existing.selectedWeightKg=Number((Number(existing.selectedWeightKg)+Number(body.selectedWeightKg)).toFixed(3));existing.quantity=1}else existing.quantity+=body.quantity}else items.push({id:`pending-${uuid()}`,productId:product.id,variantId:body.variantId||null,quantity:body.quantity,selectedWeightKg:body.selectedWeightKg,product});state.cart={...state.cart,items}}
async function addProduct(button,product,body,source,onSuccess=()=>{}){if(state.cartPending.has(product.id))return;const before=cartCopy();state.cartPending.add(product.id);optimisticAdd(product,body);patchCart();flyToCart(source);setButtonLoading(button,true,"Adding…");try{state.cart=await api("/cart/items",{method:"POST",body:JSON.stringify(body)});state.cartPending.delete(product.id);patchCart();onSuccess();toast(`${product.name} added.`)}catch(error){state.cart=before;state.cartPending.delete(product.id);patchCart();toast(error.message,"error")}finally{setButtonLoading(button,false)}}
async function quickAdd(button,id){const p=state.products.find(x=>x.id===id);if(p.pricingType==="VARIANT"){showProduct(button,id);return}const body={productId:id,quantity:1,selectedWeightKg:p.pricingType==="WEIGHT"?p.minimumOrderWeight:null};await addProduct(button,p,body,button.closest(".product-card").querySelector("img"))}
function changeCart(button){const line=state.cart.items.find(x=>String(x.id)===button.dataset.cartStep);if(!line)return;const delta=Number(button.dataset.delta),weight=line.product.pricingType==="WEIGHT";if(weight){const step=Number(line.product.minimumOrderWeight),next=Number((Number(line.selectedWeightKg)+delta*step).toFixed(3));if(next<=0){removeCartItem(line.id);return}if(next>Number(line.product.maximumOrderWeight)){toast(`Maximum weight is ${line.product.maximumOrderWeight} kg.`,"error");return}line.selectedWeightKg=next;line.quantity=1}else{line.quantity+=delta;if(line.quantity<=0){removeCartItem(line.id);return}}patchCart();scheduleCartSave(line.id)}
function scheduleCartSave(id){const key=String(id),entry=state.cartSaves.get(key)||{version:0,running:false,timer:null};entry.version++;clearTimeout(entry.timer);entry.timer=setTimeout(()=>persistCartItem(key),180);state.cartSaves.set(key,entry)}
async function persistCartItem(key){const entry=state.cartSaves.get(key),line=state.cart.items.find(x=>String(x.id)===key);if(!entry||!line)return;if(entry.running){entry.queued=true;return}entry.running=true;entry.queued=false;const version=entry.version,payload={productId:line.productId,variantId:line.variantId,quantity:line.quantity,selectedWeightKg:line.selectedWeightKg};try{const result=await api(`/cart/items/${key}`,{method:"PATCH",body:JSON.stringify(payload)});if(entry.version===version){state.cart=result;patchCart()}}catch(error){if(entry.version===version){state.cart=await api("/cart").catch(()=>state.cart);patchCart();toast(error.message,"error")}}finally{entry.running=false;if(entry.queued||entry.version!==version)persistCartItem(key);else state.cartSaves.delete(key)}}
async function removeCartItem(id){const key=String(id),before=cartCopy();state.cart={...state.cart,items:state.cart.items.filter(x=>String(x.id)!==key)};patchCart();try{state.cart=await api(`/cart/items/${key}`,{method:"DELETE"});patchCart()}catch(error){state.cart=before;patchCart();toast(error.message,"error")}}
function showProduct(trigger,id){const p=state.products.find(x=>x.id===id),modal=openModal(trigger,{title:p.name,wide:true,body:`<div class="product-detail"><img src="${esc(p.imageUrl)}" alt="${esc(p.name)}"><div><span class="section-kicker">${esc(p.categoryName)}</span><p>${esc(p.description)}</p><div class="badge-row">${badges(p)}</div><form id="product-form">${p.pricingType==="VARIANT"?`<div class="field"><label for="variant">Variant</label><select id="variant" name="variantId" class="select">${p.variants.filter(v=>v.active&&Number(v.stockQuantity)>0).map(v=>`<option value="${v.id}">${esc(v.label)} / ${money(v.unitPrice||v.pricePerKg)}</option>`).join("")}</select></div>`:""}${p.pricingType==="WEIGHT"?`<div class="field"><label for="selected-weight">Weight (kg)</label><input class="input" id="selected-weight" name="selectedWeightKg" type="number" min="${p.minimumOrderWeight}" max="${p.maximumOrderWeight}" step="0.1" value="${p.minimumOrderWeight}"></div>`:`<div class="field"><label for="quantity">Quantity</label><input class="input" id="quantity" name="quantity" type="number" min="1" max="10" value="1"></div>`}<div class="stock-line"><span>Available</span><strong data-stock>${stockOf(p,p.variants[0]?.id)} units</strong></div><div class="form-error" role="alert"></div><button type="submit" class="btn btn-accent btn-wide">Add to cart</button></form></div></div>`});
  const form=modal.panel.querySelector("form"),variant=form.querySelector("[name=variantId]");variant?.addEventListener("change",()=>modal.panel.querySelector("[data-stock]").textContent=`${stockOf(p,variant.value)} units`);
  form.addEventListener("submit",async event=>{event.preventDefault();const values=Object.fromEntries(new FormData(form)),body={productId:p.id,variantId:values.variantId?Number(values.variantId):null,quantity:Number(values.quantity||1),selectedWeightKg:values.selectedWeightKg?Number(values.selectedWeightKg):null},button=form.querySelector('button[type="submit"],button:last-child');await addProduct(button,p,body,modal.panel.querySelector(".product-detail>img"),()=>modal.close())});
}

function addressModal(trigger){const modal=openModal(trigger,{title:"Delivery addresses",body:`<div class="address-list">${state.addresses.map(a=>`<button type="button" class="address-option" data-address-default="${a.id}"><strong>${esc(a.label)}</strong><span>${esc(a.addressLine)}</span>${a.isDefault?"<small>Default</small>":""}</button>`).join("")}</div><button type="button" class="btn btn-soft btn-wide" data-new-address>Add another address</button>`});modal.panel.querySelectorAll("[data-address-default]").forEach(button=>button.addEventListener("click",async()=>{const a=state.addresses.find(x=>x.id===Number(button.dataset.addressDefault));button.disabled=true;try{const saved=await api(`/addresses/${a.id}`,{method:"PUT",body:JSON.stringify({label:a.label,addressLine:a.addressLine,landmark:a.landmark,instructions:a.instructions,latitude:a.latitude,longitude:a.longitude,zoneId:a.zoneId,isDefault:true})});state.addresses=state.addresses.map(x=>x.id===saved.id?saved:{...x,isDefault:false});modal.close();patchLocation();toast("Delivery address selected.")}catch(error){button.disabled=false;toast(error.message,"error")}}));modal.panel.querySelector("[data-new-address]")?.addEventListener("click",()=>{modal.close();editAddress(trigger)});}
function editAddress(trigger){const modal=openModal(trigger,{title:"Add delivery address",body:`<form id="address-form"><div class="field"><label>Label</label><select class="select" name="label"><option>HOME</option><option>WORK</option><option>OTHER</option></select></div><div class="field"><label>Address</label><input class="input" name="addressLine" maxlength="240" required></div><div class="field"><label>Landmark</label><input class="input" name="landmark" maxlength="120"></div><div class="field"><label>Delivery instructions</label><textarea class="textarea" name="instructions" maxlength="240"></textarea></div><div class="field"><label>Zone</label><select class="select" name="zoneId">${zoneOptions()}</select></div><input type="hidden" name="latitude"><input type="hidden" name="longitude"><label class="check-row"><input type="checkbox" name="isDefault" checked> Make this my default</label><button type="button" class="btn btn-soft btn-wide" data-detect>Use current location</button><div class="form-error" role="alert"></div><button type="submit" class="btn btn-accent btn-wide">Save address</button></form>`});const form=modal.panel.querySelector("form");modal.panel.querySelector("[data-detect]").addEventListener("click",()=>detectLocation(form));form.addEventListener("submit",async event=>{event.preventDefault();const button=form.querySelector('button[type="submit"]'),v=Object.fromEntries(new FormData(form)),coords=ZONE_COORDS[v.zoneId];button.disabled=true;try{const saved=await api("/addresses",{method:"POST",body:JSON.stringify({...v,zoneId:Number(v.zoneId),latitude:Number(v.latitude||coords[0]),longitude:Number(v.longitude||coords[1]),isDefault:Boolean(v.isDefault)})});if(saved.isDefault)state.addresses=state.addresses.map(x=>({...x,isDefault:false}));state.addresses.push(saved);modal.close();patchLocation();toast("Address saved.")}catch(error){form.querySelector(".form-error").textContent=error.message;button.disabled=false}})}
function detectLocation(form){const button=form.querySelector("[data-detect]");if(!navigator.geolocation){toast("Location detection is unavailable. Enter the address manually.","error");return}button.disabled=true;button.textContent="Detecting…";navigator.geolocation.getCurrentPosition(position=>{form.elements.latitude.value=position.coords.latitude;form.elements.longitude.value=position.coords.longitude;button.textContent=`Located within ${Math.round(position.coords.accuracy)} m`;button.disabled=false},code=>{button.textContent="Use current location";button.disabled=false;toast(code.code===1?"Location permission was denied. Manual entry remains available.":"GPS location could not be read. Enter it manually.","error")},{enableHighAccuracy:true,timeout:9000,maximumAge:30000})}
function zoneOptions(){return state.zones.map(z=>`<option value="${z.id}">${esc(z.name)}</option>`).join("")}

function checkout(trigger){
  const delivery=state.addresses.find(a=>a.isDefault)||state.addresses[0],key=uuid();let latestQuote=null,quoteTimer,previous=null,quoteController,quoteSequence=0;
  const modal=openModal(trigger,{title:"Build the delivery",wide:true,body:`<div class="checkout-grid"><form id="checkout-form" class="checkout-form"><section><span class="section-kicker">Route</span><div class="field"><label>Pickup</label><input class="input" name="pickupAddress" value="Relay Market, Church Street" required></div><div class="field"><label>Delivery address</label><input class="input" name="deliveryAddress" value="${esc(delivery?.addressLine||"")}" required></div><div class="form-pair"><div class="field"><label>Pickup zone</label><select class="select" name="pickupZoneId">${zoneOptions()}</select></div><div class="field"><label>Delivery zone</label><select class="select" name="deliveryZoneId">${zoneOptions()}</select></div></div><button type="button" class="btn btn-soft btn-wide" data-detect>Detect delivery location</button></section><section><span class="section-kicker">Service</span><div class="field"><label>Priority</label><select class="select" name="priority"><option>STANDARD</option><option>EXPRESS</option><option>CRITICAL</option></select></div><div class="field"><label>Coupon</label><input class="input" name="couponCode" placeholder="WELCOME10"></div><label class="switch-row"><span><strong>Send as a gift</strong><small>Wrap, message and schedule it</small></span><span class="switch"><input type="checkbox" name="gift"><i></i></span></label><div class="gift-fields" data-gift hidden>${giftFields()}</div></section><div class="form-error" role="alert"></div></form><aside class="quote-panel" data-quote>${quoteSkeleton()}</aside></div>`});
  const form=modal.panel.querySelector("form");form.elements.pickupZoneId.value="3";if(delivery)form.elements.deliveryZoneId.value=String(delivery.zoneId);
  const quote=async()=>{clearTimeout(quoteTimer);quoteController?.abort();quoteController=new AbortController();const sequence=++quoteSequence;latestQuote=null;modal.panel.querySelector("[data-quote]").innerHTML=quoteSkeleton();try{const request=quoteRequest(form,delivery);const value=await api("/pricing/quote",{method:"POST",body:JSON.stringify(request),signal:quoteController.signal});if(sequence!==quoteSequence)return;latestQuote=value;modal.panel.querySelector("[data-quote]").innerHTML=quoteMarkup(value,previous);previous=value;modal.panel.querySelector("[data-confirm]").addEventListener("click",event=>confirmOrder(event.currentTarget,modal,value,request,key))}catch(error){if(error.name==="AbortError"||sequence!==quoteSequence)return;modal.panel.querySelector("[data-quote]").innerHTML=`<div class="quote-error"><strong>Price unavailable</strong><span>${esc(error.message)}</span></div>`}};
  modal.layer.addEventListener("modalclose",()=>{clearTimeout(quoteTimer);quoteController?.abort()},{once:true});
  const debounce=()=>{clearTimeout(quoteTimer);quoteTimer=setTimeout(quote,380)};form.addEventListener("input",debounce);form.addEventListener("change",event=>{if(event.target.name==="gift"){form.querySelector("[data-gift]").hidden=!event.target.checked;if(event.target.checked){const tomorrow=new Date(Date.now()+86400000);form.elements.scheduleDate.value=tomorrow.toISOString().slice(0,10);loadSlots(form)}}if(event.target.name==="scheduleDate")loadSlots(form);debounce()});
  form.querySelector("[data-detect]").addEventListener("click",()=>detectCheckoutLocation(form,debounce));quote();
}
function giftFields(){return `<div class="form-pair"><div class="field"><label>Recipient</label><input class="input" name="recipientName" maxlength="100"></div><div class="field"><label>Phone</label><input class="input" name="recipientPhone" maxlength="16" placeholder="+919876543210"></div></div><div class="field"><label>Sender name</label><input class="input" name="senderName" maxlength="100" value="${esc(state.session.user.name)}"></div><div class="field"><label>Occasion</label><select class="select" name="occasion"><option>BIRTHDAY</option><option>ANNIVERSARY</option><option>FESTIVAL</option><option>WEDDING</option><option>GRADUATION</option><option>CONGRATULATIONS</option><option>THANK_YOU</option><option>SURPRISE</option><option>CUSTOM</option></select></div><div class="field"><label>Gift message</label><textarea class="textarea" name="giftMessage" maxlength="500"></textarea></div><div class="field"><label>Delivery instructions</label><textarea class="textarea" name="deliveryInstructions" maxlength="500"></textarea></div><div class="form-pair"><div class="field"><label>Wrapping</label><select class="select" name="wrappingStyle"><option>ECO</option><option>STANDARD</option><option>PREMIUM</option></select></div><div class="field"><label>Card</label><select class="select" name="cardStyle"><option>MINIMAL</option><option>CELEBRATION</option><option>FLORAL</option></select></div></div><div class="form-pair"><div class="field"><label>Delivery date</label><input class="input" type="date" name="scheduleDate"></div><div class="field"><label>Time slot</label><select class="select" name="slot"><option value="">Choose a date</option></select></div></div><div class="check-grid"><label><input type="checkbox" name="hideSender"> Hide sender</label><label><input type="checkbox" name="hidePrice" checked> Hide price</label><label><input type="checkbox" name="surpriseDelivery"> Surprise delivery</label><label><input type="checkbox" name="recipientOtpRequired"> Recipient OTP</label></div>`}
async function loadSlots(form){const dateValue=form.elements.scheduleDate.value;if(!dateValue)return;try{const slots=await api(`/delivery/slots?date=${encodeURIComponent(dateValue)}&timezone=Asia%2FKolkata`);form.elements.slot.innerHTML=slots.length?slots.map(s=>`<option value="${s.startTime}|${s.endTime}" ${s.remainingCapacity?"":"disabled"}>${esc(s.name)} / ${s.startTime}-${s.endTime} / ${s.remainingCapacity} left</option>`).join(""):'<option value="">No slots available</option>'}catch(error){toast(error.message,"error")}}
function detectCheckoutLocation(form,onChange){if(!navigator.geolocation){toast("Location detection is unavailable. Use the address and zone fields.","error");return}const button=form.querySelector("[data-detect]");button.disabled=true;navigator.geolocation.getCurrentPosition(position=>{const lat=position.coords.latitude,lng=position.coords.longitude;form.dataset.deliveryLat=lat;form.dataset.deliveryLng=lng;if(!form.elements.deliveryAddress.value.trim())form.elements.deliveryAddress.value=`Current location (${lat.toFixed(5)}, ${lng.toFixed(5)})`;button.textContent=`GPS accuracy ${Math.round(position.coords.accuracy)} m`;button.disabled=false;onChange()},error=>{button.disabled=false;toast(error.code===1?"Location permission denied. Manual delivery entry is available.":"GPS response was too slow or unavailable.","error")},{enableHighAccuracy:true,timeout:9000,maximumAge:30000})}
function quoteRequest(form,address){const v=Object.fromEntries(new FormData(form)),pickup=ZONE_COORDS[v.pickupZoneId],drop=ZONE_COORDS[v.deliveryZoneId],gift=Boolean(v.gift);let scheduledAt=null,windowStart=null,windowEnd=null;if(gift&&v.scheduleDate&&v.slot){const [start,end]=v.slot.split("|");scheduledAt=new Date(`${v.scheduleDate}T${start}:00+05:30`).toISOString();windowStart=scheduledAt;windowEnd=new Date(`${v.scheduleDate}T${end}:00+05:30`).toISOString()}return{cartItems:state.cart.items.map(line=>({productId:line.productId,variantId:line.variantId,quantity:line.quantity,selectedWeightKg:line.selectedWeightKg})),pickupLocation:{address:v.pickupAddress,latitude:pickup[0],longitude:pickup[1],zoneId:Number(v.pickupZoneId)},deliveryLocation:{address:v.deliveryAddress,latitude:Number(form.dataset.deliveryLat||address?.latitude||drop[0]),longitude:Number(form.dataset.deliveryLng||address?.longitude||drop[1]),zoneId:Number(v.deliveryZoneId),landmark:address?.landmark||null,instructions:address?.instructions||null},priority:v.priority,giftOptions:gift?{enabled:true,recipientName:v.recipientName,recipientPhone:v.recipientPhone,occasion:v.occasion,giftMessage:v.giftMessage,senderName:v.senderName||state.session.user.name,hideSender:Boolean(v.hideSender),hidePrice:Boolean(v.hidePrice),wrappingStyle:v.wrappingStyle,cardStyle:v.cardStyle,surpriseDelivery:Boolean(v.surpriseDelivery),recipientOtpRequired:Boolean(v.recipientOtpRequired),deliveryInstructions:v.deliveryInstructions}:null,scheduledAt,deliveryWindowStart:windowStart,deliveryWindowEnd:windowEnd,timezone:"Asia/Kolkata",couponCode:v.couponCode||null}}
function quoteSkeleton(){return `<span class="section-kicker">Verified price</span><div class="quote-shimmer"></div><div class="quote-shimmer short"></div><div class="quote-shimmer"></div>`}
function quoteMarkup(q,previous){const delta=previous?`${Number(q.distanceKm)!==Number(previous.distanceKm)?`<p>Distance changed ${previous.distanceKm} → ${q.distanceKm} km</p>`:""}${Number(q.totalWeightKg)!==Number(previous.totalWeightKg)?`<p>Weight changed ${previous.totalWeightKg} → ${q.totalWeightKg} kg</p>`:""}`:"";return `<span class="section-kicker">Verified for 10 minutes</span><h3>${q.distanceKm} km / ${q.totalWeightKg} kg</h3><div class="quote-delta">${delta}</div><div class="charge-list">${q.chargeLines.map(line=>`<div><span>${esc(line.label)}</span><strong>${money(line.amount)}</strong></div>`).join("")}</div><div class="quote-total"><span>Payable</span><strong>${money(q.finalPayableAmount)}</strong></div><button type="button" class="btn btn-accent btn-wide" data-confirm>Review and place order</button>`}
function confirmOrder(trigger,parent,q,request,key){const gift=request.giftOptions?.enabled,modal=openModal(trigger,{title:"Confirm the route",body:`<div class="confirmation"><div class="confirm-route"><span>Pickup</span><strong>${esc(request.pickupLocation.address)}</strong><span>Delivery</span><strong>${esc(request.deliveryLocation.address)}</strong></div><div class="confirm-metrics"><div><small>Items</small><strong>${state.cart.items.reduce((n,x)=>n+x.quantity,0)}</strong></div><div><small>Weight</small><strong>${q.totalWeightKg} kg</strong></div><div><small>Distance</small><strong>${q.distanceKm} km</strong></div></div>${gift?`<div class="gift-confirm"><span class="gift-badge">Gift / ${esc(formatStatus(request.giftOptions.occasion))}</span><strong>${esc(request.giftOptions.recipientName)}</strong><span>${date(request.scheduledAt)}</span></div>`:""}<div class="charge-list">${q.chargeLines.map(line=>`<div><span>${esc(line.label)}</span><strong>${money(line.amount)}</strong></div>`).join("")}</div><button type="button" class="btn btn-accent btn-wide" data-place>Place Order • Pay ${money(q.finalPayableAmount)}</button><div class="form-error" role="alert"></div></div>`});modal.panel.querySelector("[data-place]").addEventListener("click",async event=>{const button=event.currentTarget;setButtonLoading(button,true,"Placing order…");try{const result=await api("/orders",{method:"POST",headers:{"Idempotency-Key":key},body:JSON.stringify({quoteId:q.quoteId})});state.cart={...state.cart,items:[]};state.orders=[result.order,...state.orders.filter(order=>order.id!==result.order.id)];modal.close();parent.close();patchCart();patchHistory();toast(result.order.status==="SCHEDULED"?"Your gift is scheduled.":"Order placed. Your delivery code is ready in order details.")}catch(error){modal.panel.querySelector(".form-error").textContent=error.message}finally{setButtonLoading(button,false)}})}

async function showOrder(trigger,id){const modal=openModal(trigger,{title:`Order RLY-${String(id).padStart(4,"0")}`,wide:true,body:'<div class="skeleton"></div>'});try{const data=await api(`/orders/${id}`),o=data.order,current=STATUS_FLOW.indexOf(o.status);if(!modal.isOpen)return;modal.panel.querySelector(".modal-body").innerHTML=`<div class="order-detail-head"><span class="status-pill" data-status="${o.status}">${formatStatus(o.status)}</span><strong>${money(o.price)}</strong></div><div class="timeline">${STATUS_FLOW.map((step,index)=>`<span class="timeline-step ${index<=current?"is-done":""}">${formatStatus(step)}</span>`).join("")}</div>${data.deliveryCode?deliveryCodeMarkup(data.deliveryCode,data.deliveryCodeMessage):""}${o.orderType==="GIFT"?`<div class="gift-confirm"><span class="gift-badge">Gift / ${esc(formatStatus(data.gift?.occasion))}</span><strong>${esc(data.gift?.recipientName)}</strong><span>${date(o.scheduledDeliveryAt)}</span></div>`:""}<div class="line-items">${data.items.map(item=>`<div><span>${esc(item.productName)}${item.variantLabel?` / ${esc(item.variantLabel)}`:""}</span><strong>${money(item.lineSubtotal)}</strong></div>`).join("")}</div><div class="route-summary"><span>${data.route.distanceKm} km</span><span>${data.route.etaMinutes} min baseline ETA</span></div><div class="detail-actions">${["ASSIGNED","PICKED_UP","OUT_FOR_DELIVERY","DELIVERY_VERIFICATION"].includes(o.status)?'<button type="button" class="btn btn-accent" data-track>Track live</button>':""}${["SCHEDULED","PLACED","CONFIRMED","PACKED","ASSIGNED"].includes(o.status)?'<button type="button" class="btn btn-danger" data-cancel>Cancel order</button>':""}</div>`;modal.panel.querySelector("[data-track]")?.addEventListener("click",event=>trackOrder(event.currentTarget,id));modal.panel.querySelector("[data-cancel]")?.addEventListener("click",async event=>{const button=event.currentTarget;setButtonLoading(button,true,"Cancelling…");try{const result=await api(`/orders/${id}/status`,{method:"POST",body:JSON.stringify({status:"CANCELLED"})});const index=state.orders.findIndex(order=>order.id===id);if(index>=0)state.orders[index]=result.order;modal.close();patchHistory();toast("Order cancelled and inventory released.")}catch(error){toast(error.message,"error")}finally{setButtonLoading(button,false)}})}catch(error){if(modal.isOpen)modal.panel.querySelector(".modal-body").innerHTML=`<div class="empty-state"><div><strong>Order unavailable</strong>${esc(error.message)}</div></div>`}}
function deliveryCodeMarkup(code,message="Share this code only when you receive your order."){return `<section class="delivery-code" aria-label="Delivery verification code"><span>Delivery verification code</span><strong>${esc(code)}</strong><p>${esc(message)}</p></section>`}

class FallbackMapAdapter{
  constructor(root){this.root=root;root.innerHTML=`<div class="fallback-map"><div class="map-grid"></div><div class="map-route-line"></div><span class="map-marker pickup" title="Pickup">P</span><span class="map-marker agent" title="Courier">C</span><span class="map-marker drop" title="Delivery">D</span></div>`}
  update(data){const points=[data.pickup,data.drop,data.location].filter(Boolean),lats=points.map(p=>p.latitude),lngs=points.map(p=>p.longitude),minLat=Math.min(...lats),maxLat=Math.max(...lats),minLng=Math.min(...lngs),maxLng=Math.max(...lngs),position=p=>({x:10+80*(p.longitude-minLng)/Math.max(.0001,maxLng-minLng),y:90-80*(p.latitude-minLat)/Math.max(.0001,maxLat-minLat)});for(const [name,p] of [["pickup",data.pickup],["drop",data.drop],["agent",data.location||data.pickup]]){const pos=position(p),el=this.root.querySelector(`.${name}`);el.style.transform=`translate(${pos.x}cqw,${pos.y}cqh)`}this.root.querySelector(".agent").classList.toggle("is-stale",data.stale)}
}
export const MapAdapter={create:root=>new FallbackMapAdapter(root)};
function trackOrder(trigger,id){let open=true,adapter,timer,controller;const modal=openModal(trigger,{title:"Live delivery",wide:true,body:`<div class="tracking-layout"><div data-map></div><aside data-track-info>${skeleton(1)}</aside></div>`});adapter=MapAdapter.create(modal.panel.querySelector("[data-map]"));modal.layer.addEventListener("modalclose",()=>{open=false;clearTimeout(timer);controller?.abort()},{once:true});const poll=async()=>{if(!open)return;controller=new AbortController();try{const data=await api(`/orders/${id}/tracking`,{signal:controller.signal});if(!open)return;adapter.update(data);modal.panel.querySelector("[data-track-info]").innerHTML=`<span class="status-pill" data-status="${data.status}">${formatStatus(data.status)}</span><h3>${data.eta?.label||"ETA pending"}</h3><p>${data.remainingDistanceKm??"-"} km remaining</p>${data.deliveryCode?deliveryCodeMarkup(data.deliveryCode,data.deliveryCodeMessage):""}${data.agent?`<div class="agent-identity"><strong>${esc(data.agent.name)}</strong><span>${esc(data.agent.vehicleType)} / ${esc(data.agent.maskedContact)}</span></div>`:""}<dl class="tracking-meta"><div><dt>Last signal</dt><dd>${data.lastUpdatedAt?date(data.lastUpdatedAt):"Courier has not shared location"}</dd></div><div><dt>Accuracy</dt><dd>${data.location?`${Math.round(data.location.accuracyMeters)} m`:"-"}</dd></div></dl><a class="btn btn-soft btn-wide" href="${esc(data.externalMapUrl)}" target="_blank" rel="noopener">Open destination map</a>`}catch(error){if(error.name!=="AbortError")toast(error.message,"error")}if(open)timer=setTimeout(poll,7000)};poll()}

async function loadAgent(showSkeleton=true){if(showSkeleton){app.innerHTML=`${topbar("Courier run")}<main class="workspace">${skeleton()}</main>`;bindGlobal()}const [agent,orders]=await Promise.all([api("/agents/me"),api("/orders")]);const old=state.orders?.map(o=>`${o.id}:${o.status}`).join("|");state.agent=agent;state.orders=orders;if(!showSkeleton&&old&&old!==orders.map(o=>`${o.id}:${o.status}`).join("|"))toast("Your run sheet changed.");renderAgent()}
function renderAgent(){const active=state.orders.filter(o=>!["DELIVERED","CANCELLED"].includes(o.status)),capacity=Math.min(100,Number(state.agent.currentLoadKg)/Number(state.agent.maximumCapacityKg)*100);app.innerHTML=`${topbar("Courier run")}<main class="workspace"><header class="page-heading"><div><p class="eyebrow">On-road console</p><h1>${active.length?`${active.length} stops in your live run.`:"You are clear for dispatch."}</h1><p>${esc(state.agent.vehicleType)} / rating ${state.agent.rating}</p></div><label class="availability"><span><strong>Available for dispatch</strong><small>${state.agent.currentActiveOrders}/${state.agent.maximumActiveOrders} active orders</small></span><span class="switch"><input type="checkbox" data-availability ${state.agent.status!=="OFFLINE"?"checked":""}><i></i></span></label></header><div class="capacity-band"><span>Vehicle load</span><div><i style="--capacity:${capacity/100}"></i></div><strong>${state.agent.currentLoadKg} / ${state.agent.maximumCapacityKg} kg</strong></div><section><div class="section-head"><div><span class="section-kicker">Manifest</span><h2>Assigned deliveries</h2></div></div>${active.length?`<div class="job-list">${active.map(jobCard).join("")}</div>`:'<div class="empty-state"><div><strong>No active delivery</strong>Stay available to receive capacity-matched work.</div></div>'}</section></main>`;bindGlobal();document.querySelector("[data-availability]")?.addEventListener("change",toggleAvailability);document.querySelectorAll("[data-next]").forEach(b=>b.addEventListener("click",()=>advanceOrder(b)));document.querySelectorAll("[data-verify-delivery]").forEach(b=>b.addEventListener("click",()=>verifyDeliveryModal(b,Number(b.dataset.verifyDelivery),false)));document.querySelectorAll("[data-share]").forEach(b=>b.addEventListener("click",()=>startLocation(Number(b.dataset.share),b)));document.querySelectorAll("[data-stop-share]").forEach(b=>b.addEventListener("click",()=>stopLocation(true,b)))}
function jobCard(order){const next=NEXT_STATUS[order.status];return `<article class="job-card"><div><div class="order-top"><span class="order-id">RLY-${String(order.id).padStart(4,"0")}</span><span class="status-pill" data-status="${order.status}">${formatStatus(order.status)}</span></div>${order.orderType==="GIFT"?'<span class="gift-badge">Gift delivery</span>':""}<div class="route-strip"><span></span><div><small>Pickup</small>${esc(order.pickupAddress)}</div><i></i><div><small>Drop</small>${esc(order.dropAddress)}</div></div><p class="muted">${order.totalWeightKg} kg / ${order.fragile?"fragile / ":""}${order.temperatureControlled?"temperature control":"standard handling"}</p></div><div class="job-actions">${next?`<button type="button" class="btn btn-accent" data-next="${order.id}" data-status="${next}">${formatStatus(next)}</button>`:""}${order.status==="DELIVERY_VERIFICATION"?`<button type="button" class="btn btn-accent" data-verify-delivery="${order.id}">Verify Delivery</button>`:""}<button type="button" class="btn btn-soft" data-share="${order.id}">Share location</button><button type="button" class="icon-btn" data-stop-share title="Stop sharing" aria-label="Stop location sharing">■</button></div></article>`}
async function toggleAvailability(event){const control=event.currentTarget,checked=control.checked;control.disabled=true;try{await api("/agents/me/status",{method:"POST",body:JSON.stringify({status:checked?"AVAILABLE":"OFFLINE"})});toast(checked?"Available for dispatch.":"Off duty.");await loadAgent(false)}catch(error){control.checked=!checked;toast(error.message,"error")}finally{control.disabled=false}}
async function advanceOrder(button){setButtonLoading(button,true,"Updating…");try{await api(`/orders/${button.dataset.next}/status`,{method:"POST",body:JSON.stringify({status:button.dataset.status})});toast(`${formatStatus(button.dataset.status)} recorded.`);await loadAgent(false)}catch(error){toast(error.message,"error")}finally{setButtonLoading(button,false)}}
function verifyDeliveryModal(trigger,id,admin){const modal=openModal(trigger,{title:"Verify Delivery",body:`<form><div class="field"><label for="delivery-code">Customer delivery code</label><input class="input delivery-code-input" id="delivery-code" name="deliveryCode" inputmode="numeric" autocomplete="one-time-code" pattern="[0-9]{6}" minlength="6" maxlength="6" required></div>${admin?'<div class="field"><label for="delivery-reason">Manual confirmation reason</label><textarea class="textarea" id="delivery-reason" name="reason" minlength="5" maxlength="500" required></textarea></div>':""}<div class="form-error" role="alert"></div><div class="modal-form-actions"><button type="button" class="btn btn-soft" data-close>Cancel</button><button type="submit" class="btn btn-accent">Confirm Delivery</button></div></form>`});const form=modal.panel.querySelector("form");form.addEventListener("submit",async event=>{event.preventDefault();if(!form.reportValidity())return;const button=form.querySelector('button[type="submit"]'),values=Object.fromEntries(new FormData(form));setButtonLoading(button,true,"Verifying…");try{const result=await api(admin?`/admin/orders/${id}/verify-delivery`:`/orders/${id}/verify-delivery`,{method:"POST",body:JSON.stringify(values)});modal.close();if(admin)patchOrdersPanel(result.order);else{stopLocation(true);await loadAgent(false)}toast(result.message||"Delivery verified successfully.")}catch(error){form.querySelector(".form-error").textContent=error.message}finally{setButtonLoading(button,false)}})}
function startLocation(orderId,button){if(!navigator.geolocation){toast("This browser cannot share location.","error");return}stopLocation(false);state.shareOrder=orderId;button.disabled=true;button.textContent="Sharing live";state.lastLocationSent=0;state.locationWatch=navigator.geolocation.watchPosition(position=>{const now=Date.now();if(now-state.lastLocationSent<7000)return;state.lastLocationSent=now;api("/agents/me/location",{method:"POST",body:JSON.stringify({orderId,latitude:position.coords.latitude,longitude:position.coords.longitude,accuracyMeters:position.coords.accuracy,heading:position.coords.heading,speedMetersPerSecond:position.coords.speed,recordedAt:new Date(position.timestamp).toISOString()})}).catch(error=>{toast(error.message,"error");if(/Authentication|active order/.test(error.message))stopLocation(false)})},error=>{toast(error.code===1?"Location permission denied.":"Live GPS signal is unavailable.","error");stopLocation(false)},{enableHighAccuracy:true,maximumAge:3000,timeout:12000})}
function stopLocation(callApi=true,button){if(state.locationWatch!=null){navigator.geolocation.clearWatch(state.locationWatch);state.locationWatch=null}state.shareOrder=null;if(button){button.disabled=false;button.textContent="■"}if(callApi&&state.session?.user?.role==="AGENT")api("/agents/me/location",{method:"DELETE"}).catch(()=>{})}

async function loadAdmin(showSkeleton=true){if(showSkeleton){app.innerHTML=`${topbar("Dispatch control")}<main class="workspace">${skeleton()}</main>`;bindGlobal()}const [overview,live,pricingAnalytics]=await Promise.all([api("/admin/overview"),api("/admin/live-deliveries"),api("/admin/pricing-analytics")]);Object.assign(state,{overview,live,pricingAnalytics});renderAdmin()}
function renderAdmin(){const d=state.overview,low=d.products.filter(p=>p.active&&Number(p.stockQuantity)<10),scheduled=d.orders.filter(o=>o.status==="SCHEDULED");app.innerHTML=`${topbar("Dispatch control")}<main class="workspace admin"><header class="page-heading"><div><p class="eyebrow">Network operations</p><h1>Catalog, price and routes in one ledger.</h1></div><div class="admin-actions"><button type="button" class="btn btn-soft" data-add-category>New category</button><button type="button" class="btn btn-accent" data-add-product>New product</button></div></header><div class="stats-grid"><article class="stat"><span>Active routes</span><strong>${d.active}</strong></article><article class="stat"><span>Scheduled gifts</span><strong>${scheduled.length}</strong></article><article class="stat"><span>Low stock</span><strong>${low.length}</strong></article><article class="stat"><span>Live signals</span><strong>${state.live.length}</strong></article></div><div class="admin-tabs"><button type="button" class="is-active" data-admin-tab="orders">Orders</button><button type="button" data-admin-tab="catalog">Catalog</button><button type="button" data-admin-tab="pricing">Pricing</button><button type="button" data-admin-tab="schedule">Schedule & live</button></div><section data-admin-panel="orders">${ordersPanel()}</section><section data-admin-panel="catalog" hidden>${catalogPanel()}</section><section data-admin-panel="pricing" hidden>${pricingTable(d.pricingRules)}</section><section data-admin-panel="schedule" hidden>${schedulePanel(scheduled,state.live)}</section></main>`;bindGlobal();bindAdmin()}
function ordersPanel(){const f=state.adminFilters;return `<div class="admin-filterbar"><input class="input" data-order-search placeholder="Search order, customer or courier" value="${esc(f.orderSearch)}"><select class="select" data-order-status><option>ALL</option>${STATUS_FLOW.concat("CANCELLED").map(x=>`<option ${f.orderStatus===x?"selected":""}>${x}</option>`).join("")}</select></div>${ordersTable(state.overview.orders)}`}
function orderRow(o){const next=NEXT_STATUS[o.status];return `<tr data-order-row="${o.id}" data-search="${esc(`${o.id} ${o.customerName} ${o.agentName||"unassigned"}`.toLowerCase())}" data-order-status="${o.status}"><td>RLY-${String(o.id).padStart(4,"0")}${o.orderType==="GIFT"?'<span class="gift-badge">Gift</span>':""}</td><td>${esc(o.pickupZone)} → ${esc(o.dropZone)}</td><td>${o.totalWeightKg} kg</td><td>${esc(o.agentName||"Queued")}</td><td><span class="status-pill" data-status="${o.status}">${formatStatus(o.status)}</span></td><td><div class="table-actions"><button type="button" class="btn btn-mini" data-view-order="${o.id}">View</button>${o.status==="PACKED"?`<button type="button" class="btn btn-mini" data-assign="${o.id}">Auto</button><button type="button" class="btn btn-mini" data-manual-assign="${o.id}">Choose</button>`:""}${["ASSIGNED","PICKED_UP"].includes(o.status)?`<button type="button" class="btn btn-mini" data-manual-assign="${o.id}">Reassign</button>`:""}${next&&o.status!=="PACKED"?`<button type="button" class="btn btn-mini" data-admin-status="${o.id}" data-next-status="${next}">${formatStatus(next)}</button>`:""}${o.status==="DELIVERY_VERIFICATION"?`<button type="button" class="btn btn-mini" data-admin-verify="${o.id}">Verify Delivery</button>`:""}${["SCHEDULED","PLACED","CONFIRMED","PACKED","ASSIGNED"].includes(o.status)?`<button type="button" class="icon-btn" data-admin-cancel="${o.id}" title="Cancel order" aria-label="Cancel order ${o.id}">X</button>`:""}</div></td></tr>`}
function ordersTable(orders){return `<div class="table-wrap"><table><thead><tr><th>Order</th><th>Route</th><th>Load</th><th>Courier</th><th>Status</th><th>Action</th></tr></thead><tbody>${orders.map(orderRow).join("")}</tbody></table></div>`}
function catalogPanel(){const f=state.adminFilters;return `<div class="admin-filterbar"><input class="input" data-product-search placeholder="Search name or SKU" value="${esc(f.productSearch)}"><select class="select" data-product-category><option value="ALL">All categories</option>${state.overview.categories.map(c=>`<option value="${c.id}" ${String(c.id)===f.category?"selected":""}>${esc(c.name)}</option>`).join("")}</select><select class="select" data-product-stock><option value="ALL">All stock</option><option value="LOW" ${f.stock==="LOW"?"selected":""}>Low stock</option><option value="OUT" ${f.stock==="OUT"?"selected":""}>Out of stock</option><option value="INACTIVE" ${f.stock==="INACTIVE"?"selected":""}>Archived</option></select></div>${catalogTable(state.overview.products)}`}
function catalogRow(p){return `<tr data-product-row="${p.id}" data-search="${esc(`${p.name} ${p.sku}`.toLowerCase())}" data-category="${p.categoryId}" data-stock="${p.stockQuantity}" data-active="${p.active}"><td><div class="table-product"><img src="${esc(p.imageUrl)}" alt=""><span><strong>${esc(p.name)}</strong><small>${esc(p.sku)} / ${p.active?"Active":"Archived"}</small></span></div></td><td>${esc(p.categoryName)}</td><td>${priceLabel(p)}</td><td><input class="stock-input" type="number" min="0" step="0.001" value="${p.stockQuantity}" data-stock-value="${p.id}"></td><td>${badges(p)||"Standard"}</td><td><div class="table-actions"><button type="button" class="btn btn-mini" data-save-stock="${p.id}">Save</button><button type="button" class="btn btn-mini" data-add-variant="${p.id}">Variant</button><button type="button" class="icon-btn" data-edit-product="${p.id}" title="Edit product" aria-label="Edit ${esc(p.name)}">✎</button><button type="button" class="btn btn-mini" data-product-status="${p.id}" data-active="${!p.active}">${p.active?"Archive":"Activate"}</button></div></td></tr>`}
function catalogTable(products){return `<div class="table-wrap"><table><thead><tr><th>Product</th><th>Category</th><th>Pricing</th><th>Stock</th><th>Handling</th><th>Action</th></tr></thead><tbody>${products.map(catalogRow).join("")}</tbody></table></div>`}
function pricingTable(rules){return `<div class="pricing-rule-grid">${rules.map(r=>`<article class="rule-row"><div><span class="section-kicker">${formatStatus(r.type)}</span><strong>${esc(r.appliesTo||r.categoryId?`Scope ${r.appliesTo||r.categoryId}`:"Network")}</strong></div><div><small>Flat</small><strong>${money(r.flatAmount)}</strong></div><div><small>Per unit</small><strong>${money(r.perUnitAmount)}</strong></div><div><small>Percent</small><strong>${r.percentageAmount}%</strong></div><button type="button" class="icon-btn" data-edit-rule="${r.id}" title="Edit pricing rule" aria-label="Edit rule">✎</button></article>`).join("")}</div>`}
function schedulePanel(scheduled,live){return `<div class="split-panel"><section><div class="section-head"><h2>Scheduled queue</h2></div>${scheduled.length?scheduled.map(o=>`<article class="schedule-row"><span class="gift-badge">${o.orderType}</span><strong>RLY-${String(o.id).padStart(4,"0")}</strong><span>${date(o.scheduledDeliveryAt)}</span><small>${esc(o.dropAddress)}</small></article>`).join(""):'<div class="empty-state"><div><strong>No scheduled orders</strong>Future gift routes appear here.</div></div>'}</section><section><div class="section-head"><h2>Live courier signals</h2></div>${live.length?live.map(x=>`<article class="schedule-row"><span class="status-pill" data-status="${x.status}">${x.stale?"Stale":formatStatus(x.status)}</span><strong>${esc(x.agentName)}</strong><span>RLY-${String(x.orderId).padStart(4,"0")}</span><small>${date(x.recordedAt)}${x.stale?" / location signal overdue":""}</small></article>`).join(""):'<div class="empty-state"><div><strong>No active location signal</strong>Courier location signals appear here.</div></div>'}</section></div>`}
function bindAdmin(){document.querySelectorAll("[data-admin-tab]").forEach(button=>button.addEventListener("click",()=>{document.querySelectorAll("[data-admin-tab]").forEach(x=>x.classList.toggle("is-active",x===button));document.querySelectorAll("[data-admin-panel]").forEach(x=>x.hidden=x.dataset.adminPanel!==button.dataset.adminTab)}));document.querySelector("[data-add-category]").addEventListener("click",event=>categoryForm(event.currentTarget));document.querySelector("[data-add-product]").addEventListener("click",event=>productForm(event.currentTarget));document.querySelectorAll("[data-edit-rule]").forEach(b=>b.addEventListener("click",()=>ruleForm(b,state.overview.pricingRules.find(r=>r.id===Number(b.dataset.editRule)))));bindAdminCatalog();bindAdminOrders()}
function bindAdminCatalog(){const panel=document.querySelector('[data-admin-panel="catalog"]');if(!panel)return;panel.querySelectorAll("[data-edit-product]").forEach(b=>b.addEventListener("click",()=>productForm(b,state.overview.products.find(p=>p.id===Number(b.dataset.editProduct)))));panel.querySelectorAll("[data-save-stock]").forEach(b=>b.addEventListener("click",()=>saveStock(b)));panel.querySelectorAll("[data-add-variant]").forEach(b=>b.addEventListener("click",()=>variantForm(b,Number(b.dataset.addVariant))));panel.querySelectorAll("[data-product-status]").forEach(b=>b.addEventListener("click",()=>setProductStatus(b)));panel.querySelector("[data-product-search]")?.addEventListener("input",e=>{state.adminFilters.productSearch=e.target.value.toLowerCase();applyProductFilters()});panel.querySelector("[data-product-category]")?.addEventListener("change",e=>{state.adminFilters.category=e.target.value;applyProductFilters()});panel.querySelector("[data-product-stock]")?.addEventListener("change",e=>{state.adminFilters.stock=e.target.value;applyProductFilters()});applyProductFilters()}
function applyProductFilters(){const f=state.adminFilters;document.querySelectorAll("[data-product-row]").forEach(row=>{const stock=Number(row.dataset.stock),visible=(!f.productSearch||row.dataset.search.includes(f.productSearch))&&(f.category==="ALL"||row.dataset.category===f.category)&&(f.stock==="ALL"||f.stock==="LOW"&&stock<10&&row.dataset.active==="true"||f.stock==="OUT"&&stock===0||f.stock==="INACTIVE"&&row.dataset.active==="false");row.hidden=!visible})}
function bindAdminOrders(){const panel=document.querySelector('[data-admin-panel="orders"]');if(!panel)return;panel.querySelectorAll("[data-assign]").forEach(b=>b.addEventListener("click",()=>assignOrder(b)));panel.querySelectorAll("[data-manual-assign]").forEach(b=>b.addEventListener("click",()=>reassignOrder(b,Number(b.dataset.manualAssign))));panel.querySelectorAll("[data-view-order]").forEach(b=>b.addEventListener("click",()=>showOrder(b,Number(b.dataset.viewOrder))));panel.querySelectorAll("[data-admin-status]").forEach(b=>b.addEventListener("click",()=>adminOrderStatus(b,b.dataset.nextStatus)));panel.querySelectorAll("[data-admin-verify]").forEach(b=>b.addEventListener("click",()=>verifyDeliveryModal(b,Number(b.dataset.adminVerify),true)));panel.querySelectorAll("[data-admin-cancel]").forEach(b=>b.addEventListener("click",()=>adminOrderStatus(b,"CANCELLED")));panel.querySelector("[data-order-search]")?.addEventListener("input",e=>{state.adminFilters.orderSearch=e.target.value.toLowerCase();applyOrderFilters()});panel.querySelector("[data-order-status]")?.addEventListener("change",e=>{state.adminFilters.orderStatus=e.target.value;applyOrderFilters()});applyOrderFilters()}
function applyOrderFilters(){const f=state.adminFilters;document.querySelectorAll("[data-order-row]").forEach(row=>row.hidden=Boolean((f.orderSearch&&!row.dataset.search.includes(f.orderSearch))||(f.orderStatus!=="ALL"&&row.dataset.orderStatus!==f.orderStatus)))}
function patchCatalogPanel(product){if(product){const index=state.overview.products.findIndex(p=>p.id===product.id);if(index<0)state.overview.products.push(product);else state.overview.products[index]=product}const panel=document.querySelector('[data-admin-panel="catalog"]');if(panel){panel.innerHTML=catalogPanel();bindAdminCatalog()}}
function patchOrdersPanel(order){if(order){const index=state.overview.orders.findIndex(o=>o.id===order.id);if(index<0)state.overview.orders.unshift(order);else state.overview.orders[index]=order}const panel=document.querySelector('[data-admin-panel="orders"]');if(panel){panel.innerHTML=ordersPanel();bindAdminOrders()}}
function categoryForm(trigger){const modal=openModal(trigger,{title:"New category",body:`<form><div class="field"><label>Name</label><input class="input" name="name" required></div><div class="field"><label>Description</label><textarea class="textarea" name="description" required></textarea></div><div class="field"><label>Handling type</label><input class="input" name="handlingType" value="STANDARD"></div><div class="form-pair"><div class="field"><label>Max quantity</label><input class="input" name="maxQuantity" type="number" value="10"></div><div class="field"><label>Max distance km</label><input class="input" name="maxDeliveryDistanceKm" type="number" value="25"></div></div><div class="form-error"></div><button type="submit" class="btn btn-accent btn-wide">Create category</button></form>`});modal.panel.querySelector("form").addEventListener("submit",async event=>{event.preventDefault();const form=event.currentTarget,button=form.querySelector('button[type="submit"]'),v=Object.fromEntries(new FormData(form));button.disabled=true;try{const saved=await api("/admin/categories",{method:"POST",body:JSON.stringify({...v,id:0,fragileDefault:false,temperatureControlledDefault:false,requiresInsuranceDefault:false,maxQuantity:Number(v.maxQuantity),maxDeliveryDistanceKm:Number(v.maxDeliveryDistanceKm),deliveryRestrictions:null,returnEligible:true,defaultPriority:"STANDARD",active:true})});state.overview.categories.push(saved);modal.close();patchCatalogPanel();toast("Category created.")}catch(error){form.querySelector(".form-error").textContent=error.message;button.disabled=false}})}
function productForm(trigger,p){const modal=openModal(trigger,{title:p?"Edit product":"New product",wide:true,body:`<form class="form-grid"><div class="field"><label>Name</label><input class="input" name="name" value="${esc(p?.name||"")}" required></div><div class="field"><label>SKU</label><input class="input" name="sku" value="${esc(p?.sku||"")}" required></div><div class="field span-2"><label>Description</label><textarea class="textarea" name="description" required>${esc(p?.description||"")}</textarea></div><div class="field"><label>Category</label><select class="select" name="categoryId">${state.overview.categories.filter(c=>c.active).map(c=>`<option value="${c.id}" ${p?.categoryId===c.id?"selected":""}>${esc(c.name)}</option>`).join("")}</select></div><div class="field"><label>Pricing</label><select class="select" name="pricingType"><option ${p?.pricingType==="FIXED"?"selected":""}>FIXED</option><option ${p?.pricingType==="WEIGHT"?"selected":""}>WEIGHT</option><option ${p?.pricingType==="VARIANT"?"selected":""}>VARIANT</option></select></div><div class="field"><label>Unit price</label><input class="input" type="number" min="0" name="unitPrice" value="${p?.unitPrice||""}"></div><div class="field"><label>Price per kg</label><input class="input" type="number" min="0" name="pricePerKg" value="${p?.pricePerKg||""}"></div><div class="field"><label>Unit weight kg</label><input class="input" type="number" min="0" step="0.001" name="unitWeightKg" value="${p?.unitWeightKg||""}"></div><div class="field"><label>Packaging kg</label><input class="input" type="number" min="0" step="0.001" name="packagingWeightKg" value="${p?.packagingWeightKg||0}"></div><div class="field"><label>Minimum weight</label><input class="input" type="number" min="0" step="0.001" name="minimumOrderWeight" value="${p?.minimumOrderWeight||""}"></div><div class="field"><label>Maximum weight</label><input class="input" type="number" min="0" step="0.001" name="maximumOrderWeight" value="${p?.maximumOrderWeight||""}"></div><div class="field"><label>Stock</label><input class="input" type="number" min="0" step="0.001" name="stockQuantity" value="${p?.stockQuantity||0}"></div><div class="field"><label>Image URL</label><input class="input" name="imageUrl" value="${esc(p?.imageUrl||"https://images.unsplash.com/photo-1566576912321-d58ddd7a6088?w=700")}"></div><div class="check-grid span-2"><label><input type="checkbox" name="fragile" ${p?.fragile?"checked":""}> Fragile</label><label><input type="checkbox" name="temperatureControlled" ${p?.temperatureControlled?"checked":""}> Temperature control</label><label><input type="checkbox" name="requiresInsurance" ${p?.requiresInsurance?"checked":""}> Insurance</label></div><div class="form-error span-2"></div><button type="submit" class="btn btn-accent span-2">${p?"Save product":"Create product"}</button></form>`});modal.panel.querySelector("form").addEventListener("submit",async event=>{event.preventDefault();const form=event.currentTarget,button=form.querySelector('button[type="submit"]'),v=Object.fromEntries(new FormData(form)),num=x=>x===""?null:Number(x),body={id:p?.id||0,categoryId:Number(v.categoryId),categoryName:p?.categoryName||"",name:v.name,description:v.description,sku:v.sku,pricingType:v.pricingType,unitPrice:num(v.unitPrice),pricePerKg:num(v.pricePerKg),unitWeightKg:num(v.unitWeightKg),minimumOrderWeight:num(v.minimumOrderWeight),maximumOrderWeight:num(v.maximumOrderWeight),packagingWeightKg:num(v.packagingWeightKg)||0,stockQuantity:num(v.stockQuantity)||0,fragile:Boolean(v.fragile),temperatureControlled:Boolean(v.temperatureControlled),requiresInsurance:Boolean(v.requiresInsurance),shelfLifeDays:null,imageUrl:v.imageUrl,active:p?.active??true,variants:p?.variants||[]};button.disabled=true;try{const saved=await api(p?`/admin/products/${p.id}`:"/admin/products",{method:p?"PUT":"POST",body:JSON.stringify(body)});modal.close();patchCatalogPanel(saved);toast(p?"Product updated.":"Product created.")}catch(error){form.querySelector(".form-error").textContent=error.message;button.disabled=false}})}
async function saveStock(button){setButtonLoading(button,true,"Saving…");const id=Number(button.dataset.saveStock),stock=Number(document.querySelector(`[data-stock-value="${id}"]`).value);try{const saved=await api(`/admin/products/${id}/stock`,{method:"PATCH",body:JSON.stringify({variantId:null,stockQuantity:stock})});patchCatalogPanel(saved);toast("Stock updated and audited.")}catch(error){toast(error.message,"error")}finally{setButtonLoading(button,false)}}
function variantForm(trigger,productId){const modal=openModal(trigger,{title:"Add product variant",body:`<form><div class="field"><label>Label</label><input class="input" name="label" required></div><div class="field"><label>SKU</label><input class="input" name="sku" required></div><div class="form-pair"><div class="field"><label>Unit price</label><input class="input" type="number" min="0" name="unitPrice" required></div><div class="field"><label>Unit weight kg</label><input class="input" type="number" min="0.001" step="0.001" name="unitWeightKg" required></div></div><div class="field"><label>Stock</label><input class="input" type="number" min="0" name="stockQuantity" required></div><div class="form-error"></div><button type="submit" class="btn btn-accent btn-wide">Add variant</button></form>`});modal.panel.querySelector("form").addEventListener("submit",async event=>{event.preventDefault();const form=event.currentTarget,button=form.querySelector('button[type="submit"]'),v=Object.fromEntries(new FormData(form));button.disabled=true;try{await api(`/admin/products/${productId}/variants`,{method:"POST",body:JSON.stringify({id:0,productId,label:v.label,sku:v.sku,unitPrice:Number(v.unitPrice),pricePerKg:null,unitWeightKg:Number(v.unitWeightKg),minimumOrderWeight:null,maximumOrderWeight:null,stockQuantity:Number(v.stockQuantity),deliveryRestriction:null,active:true})});const saved=await api(`/admin/products/${productId}`);modal.close();patchCatalogPanel(saved);toast("Variant added.")}catch(error){form.querySelector(".form-error").textContent=error.message;button.disabled=false}})}
function ruleForm(trigger,r){const modal=openModal(trigger,{title:`Edit ${formatStatus(r.type)}`,body:`<form><div class="form-pair"><div class="field"><label>Flat amount</label><input class="input" type="number" min="0" step="0.01" name="flatAmount" value="${r.flatAmount}"></div><div class="field"><label>Per unit</label><input class="input" type="number" min="0" step="0.01" name="perUnitAmount" value="${r.perUnitAmount}"></div></div><div class="field"><label>Percentage</label><input class="input" type="number" min="0" step="0.01" name="percentageAmount" value="${r.percentageAmount}"></div><div class="form-error"></div><button type="submit" class="btn btn-accent btn-wide">Save pricing rule</button></form>`});modal.panel.querySelector("form").addEventListener("submit",async event=>{event.preventDefault();const form=event.currentTarget,button=form.querySelector('button[type="submit"]'),v=Object.fromEntries(new FormData(form));button.disabled=true;try{const saved=await api(`/admin/pricing-rules/${r.id}`,{method:"PUT",body:JSON.stringify({...r,flatAmount:Number(v.flatAmount),perUnitAmount:Number(v.perUnitAmount),percentageAmount:Number(v.percentageAmount)})}),index=state.overview.pricingRules.findIndex(rule=>rule.id===saved.id);state.overview.pricingRules[index]=saved;const panel=document.querySelector('[data-admin-panel="pricing"]');if(panel){panel.innerHTML=pricingTable(state.overview.pricingRules);panel.querySelectorAll("[data-edit-rule]").forEach(b=>b.addEventListener("click",()=>ruleForm(b,state.overview.pricingRules.find(rule=>rule.id===Number(b.dataset.editRule)))))}modal.close();toast("Pricing rule updated and audited.")}catch(error){form.querySelector(".form-error").textContent=error.message;button.disabled=false}})}
async function setProductStatus(button){setButtonLoading(button,true,"Saving…");const id=Number(button.dataset.productStatus),active=button.dataset.active==="true";try{const saved=await api(`/admin/products/${id}/status`,{method:"PATCH",body:JSON.stringify({active})});patchCatalogPanel(saved);toast(active?"Product activated.":"Product archived; order history is preserved.")}catch(error){toast(error.message,"error")}finally{setButtonLoading(button,false)}}
async function assignOrder(button){setButtonLoading(button,true,"Assigning…");try{const result=await api(`/orders/${button.dataset.assign}/assign`,{method:"POST"});patchOrdersPanel(result.order);toast("Order auto-assigned.")}catch(error){toast(error.message,"error")}finally{setButtonLoading(button,false)}}
async function reassignOrder(trigger,id){const order=state.overview.orders.find(o=>o.id===id),modal=openModal(trigger,{title:order?.status==="PACKED"?"Choose courier":"Reassign courier",body:'<div class="skeleton"></div>'});try{const agents=await api(`/admin/orders/${id}/available-agents`);if(!modal.isOpen)return;modal.panel.querySelector(".modal-body").innerHTML=agents.length?`<form><div class="field"><label>Capacity-suitable courier</label><select class="select" name="agentId">${agents.map(a=>`<option value="${a.id}">${esc(a.name)} / ${esc(a.vehicleType)} / ${a.currentLoadKg} of ${a.maximumCapacityKg} kg</option>`).join("")}</select></div><div class="form-error"></div><button type="submit" class="btn btn-accent btn-wide">Confirm assignment</button></form>`:'<div class="empty-state"><div><strong>No courier capacity</strong>Try again when a compatible vehicle is available.</div></div>';modal.panel.querySelector("form")?.addEventListener("submit",async event=>{event.preventDefault();const form=event.currentTarget,button=form.querySelector('button[type="submit"]'),agentId=Number(new FormData(form).get("agentId"));setButtonLoading(button,true,"Assigning…");try{const result=await api(order?.status==="PACKED"?`/admin/orders/${id}/assign`:`/admin/orders/${id}/reassign`,{method:"POST",body:JSON.stringify({agentId,expectedOrderVersion:order.version})});modal.close();patchOrdersPanel(result.order);toast(order?.status==="PACKED"?"Courier assigned.":"Courier reassigned.")}catch(error){form.querySelector(".form-error").textContent=error.message}finally{setButtonLoading(button,false)}})}catch(error){if(modal.isOpen)modal.panel.querySelector(".modal-body").innerHTML=`<div class="empty-state"><div><strong>Capacity unavailable</strong>${esc(error.message)}</div></div>`}}
async function adminOrderStatus(button,status){setButtonLoading(button,true,"Updating…");try{const result=await api(status==="CANCELLED"?`/admin/orders/${button.dataset.adminCancel}/cancel`:`/admin/orders/${button.dataset.adminStatus}/status`,{method:status==="CANCELLED"?"POST":"PATCH",body:JSON.stringify(status==="CANCELLED"?{}:{status})});patchOrdersPanel(result.order);toast(`${formatStatus(status)} recorded.`)}catch(error){toast(error.message,"error")}finally{setButtonLoading(button,false)}}

function renderAuth(){app.innerHTML=`<div class="auth-stage"><div class="auth-route" aria-hidden="true"></div><section class="auth-card"><div class="auth-brand"><span class="brand-mark">R/</span><div><strong>Relay market network</strong><span>Shop / route / track</span></div></div><div class="auth-tabs" role="tablist"><button type="button" class="auth-tab is-active" data-tab="login" role="tab" aria-selected="true">Sign in</button><button type="button" class="auth-tab" data-tab="register" role="tab" aria-selected="false">Create account</button><span class="tab-indicator"></span></div><div class="auth-panels"><form class="auth-panel is-active" data-panel="login"><h1>Return to your route.</h1><p>One account opens the customer, courier or operations desk.</p>${field("login-email","email","Email","email","maya@relay.demo")}${field("login-password","password","Password","password","8+ characters")}<div class="form-error" role="alert"></div><button type="submit" class="btn btn-accent btn-wide">Sign in</button><div class="demo-logins" aria-label="Development accounts"><button type="button" data-demo-login="maya@relay.demo">Customer demo</button><button type="button" data-demo-login="arjun@relay.demo">Courier demo</button><button type="button" data-demo-login="admin@relay.demo">Admin demo</button></div><p class="demo-note">Development password / Demo@123</p></form><form class="auth-panel" data-panel="register"><h1>Join the network.</h1><p>Shop the city or carry compatible routes.</p>${field("register-name","name","Name","text","Your name")}${field("register-email","email","Email","email","you@example.com")}${field("register-password","password","Password","password","Letter + number")}<div class="field"><label>Account type</label><div class="role-segments"><button type="button" class="seg-btn is-active" data-role="CUSTOMER">Customer</button><button type="button" class="seg-btn" data-role="AGENT">Courier</button></div><input type="hidden" name="role" value="CUSTOMER"></div><div class="field agent-only"><label>Vehicle</label><select class="select" name="vehicleType"><option>Bicycle</option><option>Motorcycle</option><option>Scooter</option><option>Car</option><option>Van</option><option>Mini truck</option></select></div><div class="form-error" role="alert"></div><button type="submit" class="btn btn-accent btn-wide">Create account</button></form></div></section></div>`;bindAuth()}
function field(id,name,label,type,placeholder){const autocomplete=id.startsWith("login-")?(type==="password"?"current-password":"username"):(type==="password"?"new-password":name);return `<div class="field"><label for="${id}">${label}</label><input class="input" id="${id}" name="${name}" type="${type}" autocomplete="${autocomplete}" placeholder="${placeholder}" required ${type==="password"?'minlength="8" maxlength="128"':'maxlength="180"'}><span class="field-check" aria-hidden="true">OK</span></div>`}
function bindAuth(){document.querySelectorAll("[data-tab]").forEach(tab=>tab.addEventListener("click",()=>{document.querySelectorAll("[data-tab]").forEach(x=>{const active=x===tab;x.classList.toggle("is-active",active);x.setAttribute("aria-selected",active)});document.querySelectorAll("[data-panel]").forEach(x=>x.classList.toggle("is-active",x.dataset.panel===tab.dataset.tab));document.querySelector(".tab-indicator").style.transform=`translateX(${tab.dataset.tab==="login"?0:100}%)`}));document.querySelectorAll(".input").forEach(input=>{input.addEventListener("blur",()=>input.closest(".field").classList.toggle("is-valid",input.validity.valid))});document.querySelectorAll("[data-role]").forEach(button=>button.addEventListener("click",()=>{document.querySelectorAll("[data-role]").forEach(x=>x.classList.toggle("is-active",x===button));const form=button.closest("form");form.elements.role.value=button.dataset.role;form.querySelector(".agent-only").classList.toggle("is-visible",button.dataset.role==="AGENT")}));document.querySelectorAll("[data-demo-login]").forEach(button=>button.addEventListener("click",()=>{const form=button.closest("form");form.elements.email.value=button.dataset.demoLogin;form.elements.password.value="Demo@123";form.elements.email.focus()}));document.querySelector('[data-panel="login"]').addEventListener("submit",event=>authenticate(event,"/auth/login"));document.querySelector('[data-panel="register"]').addEventListener("submit",event=>authenticate(event,"/auth/register"))}
async function authenticate(event,path){event.preventDefault();const form=event.currentTarget,button=form.querySelector('button[type="submit"]'),error=form.querySelector(".form-error");setButtonLoading(button,true,path.endsWith("login")?"Signing in…":"Creating…");error.textContent="";try{const payload=Object.fromEntries(new FormData(form));if(payload.email)payload.email=payload.email.trim();const session=await api(path,{method:"POST",body:JSON.stringify(payload)});state.session=session;localStorage.setItem("relay_session",JSON.stringify(session));location.replace({CUSTOMER:"customer.html",AGENT:"agent.html",ADMIN:"admin.html"}[session.user.role])}catch(e){error.textContent=e.message;form.classList.remove("is-shaking");void form.offsetWidth;form.classList.add("is-shaking")}finally{setButtonLoading(button,false)}}

async function pollPage(){if(state.pollInFlight)return;state.pollInFlight=true;try{if(PAGE==="customer"){const orders=await api("/orders"),before=state.orders.map(o=>`${o.id}:${o.status}`).join("|");state.orders=orders;if(before!==orders.map(o=>`${o.id}:${o.status}`).join("|")){patchHistory();toast("A delivery status changed.")}}else if(PAGE==="admin"){const [orders,live]=await Promise.all([api("/admin/orders"),api("/admin/live-deliveries")]),orderChanged=state.overview.orders.map(o=>`${o.id}:${o.status}:${o.agentId}`).join("|")!==orders.map(o=>`${o.id}:${o.status}:${o.agentId}`).join("|"),liveChanged=JSON.stringify(state.live)!==JSON.stringify(live);state.overview.orders=orders;state.live=live;if(orderChanged)patchOrdersPanel();if(liveChanged){const panel=document.querySelector('[data-admin-panel="schedule"]');if(panel)panel.innerHTML=schedulePanel(orders.filter(o=>o.status==="SCHEDULED"),live)}}else{const [agent,orders]=await Promise.all([api("/agents/me"),api("/orders")]),changed=JSON.stringify(state.agent)!==JSON.stringify(agent)||state.orders.map(o=>`${o.id}:${o.status}`).join("|")!==orders.map(o=>`${o.id}:${o.status}`).join("|");state.agent=agent;state.orders=orders;if(changed)renderAgent()}state.pollFailures=0}catch(error){if(error.name!=="AbortError"){state.pollFailures=(state.pollFailures||0)+1;if(state.pollFailures===1)toast("Live updates paused; Relay will retry.","error")}}finally{state.pollInFlight=false}}
function schedulePoll(){if(!state.polling)return;const base=document.hidden?30000:PAGE==="admin"?12000:8000,delay=Math.min(60000,base*2**Math.min(state.pollFailures||0,3));clearTimeout(state.pollTimer);state.pollTimer=setTimeout(async()=>{await pollPage();schedulePoll()},delay)}
async function boot(){if(PAGE==="auth"){if(state.session?.user){location.href={CUSTOMER:"customer.html",AGENT:"agent.html",ADMIN:"admin.html"}[state.session.user.role];return}renderAuth();return}const expected={customer:"CUSTOMER",agent:"AGENT",admin:"ADMIN"}[PAGE];if(!state.session?.token||state.session?.user?.role!==expected){logout(false);return}const loader={customer:loadCustomer,agent:loadAgent,admin:loadAdmin}[PAGE];state.polling=true;try{await loader(true);document.addEventListener("visibilitychange",schedulePoll,{passive:true});window.addEventListener("pagehide",()=>{state.polling=false;clearTimeout(state.pollTimer)},{once:true});schedulePoll()}catch(error){app.innerHTML=`<main class="fatal-state"><strong>Relay could not open this desk</strong><span>${esc(error.message)}</span><button type="button" class="btn btn-accent" data-retry>Retry</button></main>`;document.querySelector("[data-retry]").addEventListener("click",()=>boot())}}
if(typeof document!=="undefined")boot();
